var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"사샤 괜찮나? 이제 마을에 다 왔다.","JPN":"サシャ、大丈夫か？　もうすぐ村に着く。","ENG":"Sasha, are you okay? We're almost at the village.","TWN":"莎夏還好嗎？我們快到村子了。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"집에 약이 얼마나 남아있어?","JPN":"家に薬はどれぐらい残ってるの？","ENG":"Do you have your meds at home?","TWN":"家裡還有多少藥？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"으응… 아마 없을 텐데….","JPN":"ん……たぶんないと思うけど……","ENG":"Um... I think they're out...","TWN":"嗯……應該沒有了……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"약국 위치라면 알고 있어. 내가 갔다 올게.","JPN":"薬局の場所なら知ってるから私が行って来る。","ENG":"But I know where the pharmacy is. I'll go get them.","TWN":"我知道藥店在哪裡，我去一趟。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤?","JPN":"サシャ？","ENG":"Sasha?","TWN":"莎夏？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"가지마… 마브카….","JPN":"行かないで……マブカ……","ENG":"Don't go... Mavka...","TWN":"別走……瑪卡……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"약국에 다녀오는 것뿐이잖아. 여기서 잠깐만 쉬고 있어.","JPN":"薬を買ってくるだけだから。ここで休んでて。","ENG":"I'm just going to get your meds. Sit tight, and I'll be right back.","TWN":"只是去藥店而已，你在這裡稍微休息一下。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"싫어. 떠나는 거 싫어….","JPN":"いやだ。離れるのいやだ……","ENG":"No. I don't want you to go...","TWN":"不要，我不想你離開……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"우리가 다녀올게. 너는 사샤와 함께 집에 가 있어.","JPN":"私たちが行って来るから、あなたはサシャと一緒に家で待ってなさい。","ENG":"We'll go instead. You stay with Sasha.","TWN":"我們去吧，你和莎夏一起回家。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"응. 알았어.","JPN":"うん、わかった。","ENG":"Okay.","TWN":"嗯，知道了。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"올 때 아이스크림도 하나만 사주세요. 아마 없겠지만…","JPN":"帰りにアイスもお願いします……多分ないでしょうけど……","ENG":"Could you buy me some ice cream on your way back? Even though I'm sure there aren't any...","TWN":"過來的時候可不可以買個冰淇淋？雖然可能沒有……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"제발 이런 상황에는 농담하지 마.","JPN":"お願いだからこんな状況に冗談はやめて。","ENG":"How can you joke right now?","TWN":"拜託，這種情況下別開玩笑。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"후에~ 마브카 손 차가워서 기분 좋다.","JPN":"ふえ～マブカの手、冷たくて気持ちいい。","ENG":"Ahh... Mavka's cold hands feel nice.","TWN":"呼～瑪卡的手好涼，感覺真好。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"계속 이마에 올려놔 줄래?","JPN":"ずっとオデコに乗せててくれる？","ENG":"Could you keep one on my forehead?","TWN":"能一直放在我額頭上嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그리고 한쪽 손은 배 위에 올려놔 줘.","JPN":"あと片手はお腹に乗せてて。","ENG":"And the other on my stomach?","TWN":"還有一隻手放在我肚子上。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"마브카는 무거우니까 너무 힘주지 말고…","JPN":"マブカ重いから、あまり力は入れないで……","ENG":"But you're heavy, so don't put too much pressure...","TWN":"瑪卡很重，不要太用力……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"또 헛소리하면 진짜로 때릴 거야.","JPN":"またくだらないこと言ったら本当に殴るよ。","ENG":"You keep talking nonsense, and I'll really smack you.","TWN":"如果你再胡說八道，我就真的揍你一頓。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"넵……","JPN":"はい……","ENG":"Okay...","TWN":"喔喔……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그리고 애써 밝은척할 필요 없어.","JPN":"あと、無理して明るく振る舞う必要もない。","ENG":"And you don't have to keep pretending to be joyful.","TWN":"不用勉強裝作很開心的樣子。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"으응…? 내가 그래 보여…?","JPN":"ん……？　そんなふうに見える……？","ENG":"Hmm...? Do I seem like that to you...?","TWN":"嗯…？我看起來是這樣嗎…？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"에헤헤. 또 마브카가 걱정해 줬다.","JPN":"えへへ、マブカがまた心配してくれた。","ENG":"Ehehe. Mavka's worried about me again.","TWN":"嘿嘿嘿。瑪卡又在擔心我了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"빨리 잠이나 자 바보야.","JPN":"早く寝なさい、バカ。","ENG":"Just get some rest, stupid.","TWN":"快點睡覺吧，笨蛋。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"으엑! 켁! 사, 살살! 토닥토닥은 살살 해줘….","JPN":"うげっ！　ぐえ！　ちょ、ちょっと、トントンする時は優しく……","ENG":"Egh! Kuh! G-gently! Pat me gently...","TWN":"呃啊！咳！輕點！拍的時候輕點……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_03"},{"id":"L37_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"잠드는 속도는 참 빠르네.","JPN":"本当にすぐ眠るんだね。","ENG":"Well, she falls asleep fast.","TWN":"還真快睡著。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>문 열어줘. 사샤는 좀 괜찮아?</color>","JPN":"<color=#ffd34c>ドアを開けて。サシャは大丈夫？</color>","ENG":"<color=#ffd34c>Open up. Is Sasha all right?</color>","TWN":"<color=#ffd34c>幫我開門，莎夏還好嗎？</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_KNOCK_WOOD"},{"id":"L42_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"방금 잠들었어.","JPN":"今眠ったとこ。","ENG":"She just fell asleep.","TWN":"她剛剛睡著。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"자 받아.","JPN":"ほら。","ENG":"Here.","TWN":"給你。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……진짜 아이스크림까지 사 온 거야?","JPN":"……本当にアイスまで買ってきたの？","ENG":"...You really came back with ice cream?","TWN":"……你真的連冰淇淋都買來了？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"자주 일하는 사이니까, 이 정도는 그냥 호의야.","JPN":"世話になってるからね。これくらいなんてことないわ。","ENG":"We work with her a lot. I can do this much for her.","TWN":"我們合作了這麼久，這只是我的一點小心意。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"마브카. 잠깐 나와봐.","JPN":"マブカ、ちょっといい？","ENG":"Mavka, can I talk to you outside for a minute?","TWN":"瑪卡，出來一下。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"아직 할말이 남았어?","JPN":"まだ話があるの？","ENG":"You still have more to say to me?","TWN":"還有話要說嗎？"},"stage":{"bg":"CIRIN_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"마을 사람들이 왜 사샤를 아끼는 줄 알아?","JPN":"この村の人たちがサシャに優しくする理由、知ってる？","ENG":"Do you know why the village people care a lot about Sasha?","TWN":"你知道大家為什麼那麼珍惜莎夏嗎？"},"stage":{"bg":"CIRIN_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"카운터라서…?","JPN":"カウンターだから……？","ENG":"Because she's a Counter?","TWN":"因為她是制裁者……？"},"stage":{"bg":"CIRIN_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"물론 그런 이유도 있겠지.","JPN":"もちろん、それも理由の一つね。","ENG":"Yes, that would be one reason.","TWN":"當然，這也是一個原因。"},"stage":{"bg":"CIRIN_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"사샤가 시린그라드에 오기 전에는… 이 마을은 가망이 없었어.","JPN":"サシャが来る前のシリングラードには……希望がなかった。","ENG":"Before she arrived in Ciringrad... this place was hopeless.","TWN":"在莎夏來到錫林格勒之前……這個村子毫無希望。"},"stage":{"bg":"CIRIN_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"고달픈 삶에 못 이겨 서로 속이고, 빼앗는게 일상이었거든.","JPN":"貧しい生活に苦しんで……騙し合い、奪い合う日々だったのよ。","ENG":"People were deceiving and stealing from others every day, unable to overcome the hardship of living here.","TWN":"大家生活很艱難，互相欺騙、強取豪奪成了常態。"},"stage":{"bg":"CIRIN_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"그때 사샤가 이 마을에 오게 되었어.","JPN":"そんな時、サシャがこの村に流れ着いた。","ENG":"Then, Sasha came.","TWN":"那時莎夏來到了這個村子。"},"stage":{"bg":"CIRIN_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"자신의 능력으로 필요한 물건들을 만들고, 선행을 베풀며 살아갔지.","JPN":"あの子は自分の能力で必要な物を作り、それを人々と分かち合ったの。","ENG":"She used her ability to make necessary items to give to the people.","TWN":"她用自己的能力製造大家需要的物品，對大家都很好。"},"stage":{"bg":"CIRIN_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"뭐가 그리 즐거운 건지, 항상 웃는 얼굴을 하면서 말이야.","JPN":"何がそんなに楽しいのか……いつも笑顔でね。","ENG":"I don't know what was so fun about all of it, but she always had a smile on her face.","TWN":"我不知道她怎麼笑得出來，但她好像一直很快樂。"},"stage":{"bg":"CIRIN_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"솔직히… 난 전부 부질없다고 생각했는데 결과는 달랐어.","JPN":"正直全部無駄なことだと思ってたけど、違ったの。","ENG":"Honestly... I thought it was all pointless, but I was wrong.","TWN":"說實話……我本來認為她是在白費力氣，但我錯了。"},"stage":{"bg":"CIRIN_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"웃음소리도 가끔 들리게 되고, 마을은 점차 변해갔지.","JPN":"村で笑い声が聞こえるようになって……少しずつこの村は変わっていった。","ENG":"Soon, I could hear laughter on the streets as the village gradually changed.","TWN":"偶爾還能聽到的歡笑聲……說明村子逐漸改變了。"},"stage":{"bg":"CIRIN_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"믿을 수 없어… 고작 물건을 고치기만 했을 뿐인데…","JPN":"信じられない……物を直しただけなのに……","ENG":"I couldn't believe it... After all, all she did was fix a few things...","TWN":"雖然難以置信……她只是修理了一些東西而已……"},"stage":{"bg":"CIRIN_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"사샤의 능력이 정말 <color=#ffd34c>물건을 고치는 것 뿐</color>일까라는 생각이 들 정도야.","JPN":"サシャの能力って、本当に<color=#ffd34c>物を直すだけ</color>なのかなと疑ったぐらいよ。","ENG":"Now, I wonder if Sasha's ability is really just <color=#ffd34c>fixing things</color>.","TWN":"我甚至覺得莎夏的能力不僅僅是<color=#ffd34c>修東西</color>。"},"stage":{"bg":"CIRIN_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"마브카. 우린 아직 네가 의심스럽지만, 사샤는 널 상당히 신뢰하는 것 같더군.","JPN":"マブカ、俺たちはまだお前を疑っている。だが、サシャはお前をかなり信用しているようだな。","ENG":"Mavka. We are still unsure about you, but it seems that Sasha trusts you wholeheartedly.","TWN":"瑪卡，雖然我們還對你有些懷疑，但莎夏似乎非常信任你。"},"stage":{"bg":"CIRIN_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"……서로 원치 않은 순간만큼은 오지 않길 바란다.","JPN":"……お互い最悪の状況に陥ることだけは避けたいところだな。","ENG":"...I just hope that we never have to fight each other.","TWN":"……希望我們不會遇到彼此對立的時刻。"},"stage":{"bg":"CIRIN_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……알고 있어.","JPN":"……わかってる。","ENG":"...I know.","TWN":"……我知道。"},"stage":{"bg":"CIRIN_VILLAGE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤가 깨면 뭐라도 먹여야겠지.","JPN":"サシャが起きたら何か食べさせないと。","ENG":"I should feed Sasha something when she wakes up.","TWN":"莎夏醒了的話，要給她弄點吃的。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"장 보는 동안 잠에서 깨지 않았으면 좋겠는데….","JPN":"買い物に行ってる間起きないといいんだけど……","ENG":"I hope she doesn't wake up while I'm out grocery shopping...","TWN":"希望她不要在我買菜的時候醒來……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"그만 좀 해 엄마! 난 더 이상 애가 아니라 어른이라고!","JPN":"止めないでよ母さん！　私はもう子供じゃない、大人なんだよ！","ENG":"Stop it, Mom! I'm not a child anymore! I'm an adult!","TWN":"夠了，媽媽！我已經不是小孩子了，我是大人了！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MOTHER_DOLL_NPC_NULL","text":{"KOREA":"안돼! 네가 어른이 되어도 절대 민병단에 입대시킬 수 없어!","JPN":"ダメよ！　あなたが大人でも絶対民兵団には入らせないから！","ENG":"No! Even if you're an adult, I can't let you join the militia!","TWN":"不行！即使你長大了，也絕對不能讓你加入民兵團！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"칫….","JPN":"ちっ……","ENG":"Tch...","TWN":"嘖……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>엇?! 찾았다!</color>","JPN":"<color=#ffd34c>あっ！？　いたいた！</color>","ENG":"<color=#ffd34c>Oh?! There you are!</color>","TWN":"<color=#ffd34c>啊？！找到了！</color>"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"거기 은발 머리!","JPN":"そこの銀髪の人！","ENG":"Hey, silver hair!","TWN":"站住，銀頭髮的傢伙！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L31_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"그… 이름이 뭐더라?","JPN":"えっと……名前何て言うんだっけ？","ENG":"Uh... what was your name again?","TWN":"那個……你叫什麼名字？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"찾을 사람 이름도 모르니 꼬맹아?","JPN":"人探しをするのに名前も覚えてないの？　チビ。","ENG":"You don't even know the name of the person you're looking for, kid?","TWN":"連要找的人的名字都不知道嗎，小鬼？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"네가 사샤가 말했던 영웅 놀이 하는 여자애구나.","JPN":"サシャが言ってた英雄ごっこしてる女の子って、あなたのことだったのね。","ENG":"Sasha told me about you. You're the girl who plays pretend hero.","TWN":"你就是莎夏說的那個喜歡玩英雄遊戲的女生吧。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"꼬, 꼬맹이 아냐! 너도 나랑 키 똑같으면서!","JPN":"ち、チビじゃないもん！　あなただって私とそんなに変わらないでしょう！","ENG":"I-I'm not a kid! You and I are the same height!","TWN":"我，我才不是小鬼呢！你不也和我一樣高嗎！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"난 마브카. 다음부턴 기억해줘. 나한테 볼일이라도 있어?","JPN":"私はマブカ。次は覚えてね。私に何か用があるの？","ENG":"I'm Mavka. Remember that. You were looking for me?","TWN":"我是瑪卡，記好了。找我有什麼事嗎？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"응! 우리 엄마 좀 설득해 줘!","JPN":"うん！　うちの母さんを説得してほしいの！","ENG":"Right! Help me persuade my mom!","TWN":"嗯！幫我說服我媽媽吧！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MOTHER_DOLL_NPC_NULL","text":{"KOREA":"이 녀석! 사람들 많은 곳에선 뛰지 말라고 그렇게 말했잖니!","JPN":"こら！　人が多い場所では走っちゃダメだってあれほど言ったのに！","ENG":"You brat! I told you not to run around in crowded places!","TWN":"臭丫頭！不是說了在人多的地方不要亂跑嗎！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOTHER_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"MOTHER_DOLL_NPC_NULL","text":{"KOREA":"네가 사샤와 같이 있던 아이구나. 갑자기 붙잡아서 미안해.","JPN":"あなた、サシャと一緒にいた子ね。急に引き留めてごめんなさい。","ENG":"So you're the girl who was with Sasha. I apologize for my daughter's behavior.","TWN":"你是和莎夏在一起的孩子吧。這孩子突然攔住你，真是抱歉了。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOTHER_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MOTHER_DOLL_NPC_NULL","text":{"KOREA":"얘가 북방군이 아니면 민병단에 합류하겠다고 난리를 치지 뭐니….","JPN":"この子、北方軍か民兵団に入るって騒いでて困ってるのよ。","ENG":"She keeps making a fuss about wanting to join the Northern Army or the militia...","TWN":"她說如果不是北方軍，就要加入民兵團，一直在那邊跟我吵……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOTHER_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그 선전 포스터를 봤나 보네.","JPN":"あの宣伝ポスターを見たんだね。","ENG":"I assume you saw the poster.","TWN":"你應該是看了那些宣傳海報吧。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"왜 군인이 되고 싶은데?","JPN":"どうして軍人になりたいの？","ENG":"So why do you want to become a soldier?","TWN":"你為什麼想成為軍人？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"그 사람들은 국가의 영웅이잖아! 엄청 강하고 멋있다고!","JPN":"あの人たちは国の英雄でしょう？　すごく強いし、かっこいいし！","ENG":"Because they're national heroes! They're strong and cool!","TWN":"那些人是國家的英雄啊！他們非常強大，而且又帥氣！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"너도 그 포스터에 나온 언니들처럼 영웅이지? 그치?","JPN":"あなたもあのポスターの人たちみたいな英雄だよね？　ね？","ENG":"You're one of those heroes from the poster, aren't you?","TWN":"瑪卡也和海報上那些姊姊一樣，是英雄對吧？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"국가의 영웅… 시린그라드 사람이면서 그런 말을 해도 되는 거야?","JPN":"国の英雄って……シリングラードの人なのに、そんなことを言っていいの？","ENG":"A national hero... Are you sure you want to say that when you're a resident of Ciringrad?","TWN":"國家的英雄……你是錫林格勒人，說這種話可以嗎？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"입대한 다음 시린그라드로 발령받아서 마을을 지키는 군인이 될 꺼야!","JPN":"私は入隊したらシリングラードに行かせてもらって、村を守る軍人になるんだ！","ENG":"I want to join, get dispatched to Ciringrad and become a soldier who protects the village!","TWN":"入伍後我會被派到錫林格勒，成為守護村莊的軍人！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"나중엔 짱쎈 카운터가 되어서 마을을 엄청 부흥시킬 거라구!","JPN":"そしてめちゃくちゃ強いカウンターになって、村を盛り上げるの！","ENG":"I'm going to become a super-strong Counter and make this village great!","TWN":"以後我會成為超強的制裁者，讓村莊繁榮起來！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L2_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"아얏! 무, 무슨 짓이야!","JPN":"いたっ！　な、なにするのよ！","ENG":"Ouch! D-don't hit me!","TWN":"哎呀！你，你幹什麼！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_03"},{"id":"L5_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"잘 들어 이 철부지야. 먼저 군인은 발령받을 장소를 선택할 수 없어.","JPN":"世間知らずのお子ちゃま。まず軍人は、派遣先を選べない。","ENG":"Listen, brat. First of all, soldiers don't get a say on where they get assigned.","TWN":"聽好了，不懂事的小鬼。首先，軍人不能選擇被派遣的地方。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그리고 북방합의체는 여길 나라의 일부로 인정하지 않는다고 들었어.","JPN":"あと北方合意体はこの村を国の一部として認めてないと聞いた。","ENG":"Also, I heard that the Northern Union doesn't acknowledge this place as a part of its territory.","TWN":"而且我聽說北方和議會不承認這裡是國家的一部分。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"마지막으로 북방군은 네가 생각하는 것처럼 멋있는 존재도 아냐.","JPN":"最後に、北方軍はあなたが思ってるような格好いい人たちじゃない。","ENG":"Lastly, the Northern Army isn't a cool entity like you imagine it is.","TWN":"最後，北方軍並不像你想的那麼帥氣。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"자세히 말해줄 순 없지만, 포스터는 선전일 뿐이라고.","JPN":"詳しいことは言えないけど、ポスターはただの宣伝物にすぎない。","ENG":"I can't go into details, but the poster is merely propaganda.","TWN":"雖然不能詳細說明，但海報只是宣傳而已。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"꿈도 꾸지 말고 어머니 잘 보살펴 드리기나 해. 알았어?","JPN":"だから余計なことは考えないで、母さんのいうことをちゃんと聞きなさい。わかった？","ENG":"So, wake up and take good care of your mother. Got that?","TWN":"別做夢了，好好照顧你的媽媽。知道了嗎？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"마, 말도 안 돼! 내가 너보다 강해질까봐 그러는거지?!","JPN":"そ、そんなあ！　あなた、私が自分より強くなるのが怖いんでしょ！？","ENG":"N-no way! You're just scared that I might get stronger than you!","TWN":"我，我才不信！你是怕我變得比你強吧？！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GIRL_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"GIRL_DOLL_NPC_NULL","text":{"KOREA":"두고 봐! 반드시 최강이 되어서 돌아올 테니까!","JPN":"見てなさいよ！　ぜったい最強になって帰って来るから！","ENG":"Just you wait! I'll come back as the strongest soldier you've ever seen!","TWN":"等著瞧吧！我一定會成為最強的人回來的！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L13_1","type":"dialog","speaker":"MOTHER_DOLL_NPC_NULL","text":{"KOREA":"얘가 진짜! 거기서지 못하겠니!","JPN":"こら、どこ行くの！　戻って来なさい！","ENG":"Hey! You stop right there!","TWN":"你這丫頭！給我站住！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOTHER_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"하….","JPN":"はあ……","ENG":"*Sigh*","TWN":"哀……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"국가의 영웅이라니….","JPN":"国の英雄って……","ENG":"A national hero...","TWN":"什麼國家的英雄……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"아, 그러고 보니 돈도 안 챙기고 나왔네….","JPN":"あ、そういえばお金持ってくるの忘れてた……","ENG":"Oh, come to think of it, I didn't bring any money...","TWN":"啊，糟糕，沒帶錢出來……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};